import numpy as np
from collections import deque

def find_reachable_states(P, state):
    """Find all states reachable from given state using BFS."""
    n = P.shape[0]
    visited = [False] * n
    queue = deque([state])
    visited[state] = True
    reachable = {state}

    while queue:
        current = queue.popleft()
        for next_state in range(n):
            if P[current, next_state] > 0 and not visited[next_state]:
                visited[next_state] = True
                reachable.add(next_state)
                queue.append(next_state)
    return reachable

def classify_states(P):
    """Classify states as transient, recurrent, or absorbing."""
    n = P.shape[0]
    classifications = {}

    for state in range(n):
        reachable = find_reachable_states(P, state)
        # State is absorbing if P(i,i) = 1
        if P[state, state] == 1.0:
            classifications[state] = "absorbing"
        # Check if all reachable states can reach back (recurrent)
        # Using fundamental matrix approach
        elif state in reachable:
            can_return = all(
                state in find_reachable_states(P, s) 
                for s in reachable if P[s, state] > 0
            )
            if can_return:
                classifications[state] = "recurrent"
            else:
                classifications[state] = "transient"
        else:
            classifications[state] = "transient"

    return classifications

def compute_fundamental_matrix(P):
    """Compute fundamental matrix N = (I - Q)^-1 where Q is transient submatrix."""
    n = P.shape[0]
    classifications = classify_states(P)

    # Identify transient states
    transient_states = [i for i in range(n) if classifications[i] == "transient"]

    if not transient_states:
        return None, {}

    # Build Q matrix (transient to transient)
    t = len(transient_states)
    Q = np.zeros((t, t))
    for i, si in enumerate(transient_states):
        for j, sj in enumerate(transient_states):
            Q[i, j] = P[si, sj]

    # N = (I - Q)^-1
    I = np.eye(t)
    try:
        N = np.linalg.inv(I - Q)
    except:
        return None, {}

    # Map back to original state indices
    N_dict = {}
    for i, si in enumerate(transient_states):
        N_dict[si] = {sj: N[i, j] for j, sj in enumerate(transient_states)}

    return N, dict(zip(transient_states, ["transient"] * t))

# Example 1: Simple chain with absorbing state
print("=== Example 1: Chain with absorbing state ===")
P1 = np.array([
    [1.0, 0.0, 0.0],
    [0.5, 0.0, 0.5],
    [0.0, 0.5, 0.5]
])
print("Transition Matrix:")
print(P1)
print("\nState Classifications:", classify_states(P1))

# Example 2: Chain with transient states only
print("\n=== Example 2: Transient classification ===")
P2 = np.array([
    [0.3, 0.7, 0.0],
    [0.0, 0.4, 0.6],
    [0.0, 0.0, 0.5]
])
print("Transition Matrix:")
print(P2)
print("\nState Classifications:", classify_states(P2))

